interface ApiResponse<T> {
  status: number;
  data: T;
}

// A response specifically holding a string dataset.
let stringRes: ApiResponse<string> = {
  status: 200,
  data: "Success"
};

interface User { name: string; }

// We fetch a User object successfully.
let userResponse: ApiResponse<User> = {
  status: 200,
  data: { name: "Alice" }
};
